import api from '../../api';
import { GetPermissionParams, PermissionDocument } from '../models';

class InvoiceCashbackPermissionApi {
  private client = api;

  async getPermission(params: GetPermissionParams): Promise<PermissionDocument> {
    const { accountNumber } = params;
    const { data } = await this.client.get('/rewardProgram/consult-permission', {
      headers: {
        codigoCliente: accountNumber,
      },
    });
    return data;
  }

  async savePermission(document: PermissionDocument): Promise<PermissionDocument> {
    const { data } = await this.client.post('/rewardProgram/insert-permission', document);
    return data;
  }
}

export const invoiceCashbackPermissionApi = new InvoiceCashbackPermissionApi();

