    57→const addInvoiceMonth = (
    58→  qtd: number,
    59→  type: 'subtract' | 'add',
    60→  invoiceMonths: ExtractTabPropsItems[] & { dueDate?: number }[]
    61→) => {
    62→  return Array.from({ length: qtd }).map((_, index) => {
    63→    const referenceMonthObj =
    64→      invoiceMonths[type === 'subtract' ? 0 : invoiceMonths.length - 1];
    65→
    66→    const maskedDate = MaskService.toMask(
    67→      'custom',
    68→      String(referenceMonthObj?.dueDate),
    69→      {
    70→        mask: '9999/99/99',
    71→      }
    72→    );
    73→
    74→    const nextMonth = moment(maskedDate, 'YYYY/MM/DD')[type](index + 1, 'M');
    75→
    76→    return {
    77→      id: Number(nextMonth.format('YYYYMMDD')),
    78→      numMonth: nextMonth.month(),
    79→      monthActive: false,
    80→      label: nextMonth.format('MMM'),
    81→      isActive: false,
    82→      disabled: true,
    83→    };
    84→  });
    85→};
    86→
    87→const InvoiceCard = ({
