    95→  invoiceFintechRequest,
    96→  invoiceCancelRequest,
    97→  invoiceFintechReducer: {
    98→    invoicesExtract,
    99→    isLoading: isLoadingInvoice,
   100→    isError: hasErrorInvoice,
   101→  },
   102→  automaticDebtReducer,
   103→  fintechCashbackReducer,
   104→  customerReducer,
   105→  downloadInvoiceReducer,
   106→  downloadInvoiceClear,
   107→  downloadInvoiceRequest,
   108→  route,
   109→  invoicesFintechRequest,
   110→  simulationReducer,
   111→  simulationRequest,
   112→  featuresReducer,
   113→  productRequest,
   114→  requestExemptionEligibility,
   115→  requestContents,
   116→  requestActivities,
   117→  insuranceList,
   118→  pointsReducer,
   119→  requestPointsBalance,
   120→  requestPointsProducts,
   121→  requestBalance
   122→}: InvoiceCardProps) => {
