   140→      return getActiveInvoice(invoicesData)?.index || 0;
   141→    }
   142→    return 0;
   143→  };
   144→
   145→  const [currentInvoice, setCurrentInvoice] = useState(getCurrentInvoice());
   146→  const [downloadError, setDownloadError] = useState<boolean>(false);
   147→  const refCardInvoiceGroup = useRef<FlatList | null>(null);
   148→  const debounceInvoice = useRef<NodeJS.Timeout | null>(null);
   149→  const debounceScroll = useRef<NodeJS.Timeout | null>(null);
   150→
   151→  const isAutoDebt = !!automaticDebtReducer.data?.isActive;
   152→
   153→  const handleNavigateToPayInvoice = (
   154→    content_id: string,
   155→    payment: propsItems
   156→  ) => {
   157→    eventSelectContent({
   158→      content_type: 'cta',
   159→      content_id,
   160→      location_1: 'autosservico',
   161→      location_2: 'spmais',
   162→      location_3: 'faturas_spmais',
   163→    });
   164→    navigation.navigate('PayInvoice', {
   165→      payment,
   166→      analytics: {
   167→        screen_name: 'spmais',
   168→        screen_class: 'faturas_spmais',
   169→        screen_bussines: 'autosservico',
   170→        screen_info: {
   171→          location_1: 'autosservico',
   172→          location_2: 'spmais',
   173→          location_3: 'faturas_spmais',
   174→        },
   175→      },
   176→    });
   177→  };
   178→
   179→  const selectedBenefit = useRef<Benefit>(null);
   180→
   181→  const { benefits } = useContents(handleCheckExemptionEligibility);
   182→
   183→  useEffect(() => {
   184→    if (
   185→      Reflect.has(benefits, 'MONTHLY_FEE_EXEMPTION') &&
   186→      !selectedBenefit.current
   187→    ) {
   188→      selectedBenefit.current = benefits?.MONTHLY_FEE_EXEMPTION;
   189→    }
   190→  }, [selectedBenefit, benefits]);
   191→
   192→  const handleOpenBenefitsModalize = useCallback(() => {
   193→    benefitsModalizeRef.current?.open?.();
   194→  }, [benefitsModalizeRef]);
   195→
   196→  const invoicesCard: InvoiceCardViewProps['invoicesCard'] = useMemo(
   197→    () =>
   198→      invoicesData
   199→        ?.map((invoice) => {
   200→          const invoiceCardObj: InvoiceCardViewProps['invoicesCard'][number] = {
   201→            ...invoiceCardDataRebrand(
   202→              simulationReducer.isLoading,
   203→              !!simulationReducer.data,
   204→              !(invoicesData.length === 1 && invoice.Situacao === 'default'),
   205→              !!invoice?.ParcelamentoDisponivel
   206→            )[(invoice?.Situacao ?? 'default') as InvoiceItemsType],
   207→            id: invoice.Fechamento,
   208→            dueDate: invoice.Vencimento,
   209→            balance: formatToCurrency(invoice.Valor),
   210→            leftItems: [
   211→              {
   212→                label: 'Vencimento',
   213→                labelColor: 'INTENSE_COLOR_04',
   214→                value: invoice.VencimentoOriginal
   215→                  ? moment(invoice.VencimentoOriginal).format('DD [de] MMMM')
   216→                  : '-',
   217→                valueColor: 'BRAND_COMPLEMENT_01',
   218→              },
   219→            ],
   220→            rightItems: [
   221→              {
   222→                label: 'Pagamento mínimo',
   223→                labelColor: 'INTENSE_COLOR_04',
   224→                value: formatToCurrency(invoice.ValorPgtoMinimo),
   225→                valueColor: 'BRAND_COMPLEMENT_01',
   226→              },
   227→            ],
   228→            ...(invoice.MelhorDiaCompra &&
   229→              (invoice.Situacao === 'closed' ||
   230→                invoice.Situacao === 'open' ||
   231→                invoice.Situacao === 'default') && {
   232→                description: `Melhor dia de compra: ${moment(
   233→                  invoice.MelhorDiaCompra
   234→                ).format('DD/MM')}`,
   235→                descriptionIcon: 'icon-calendar',
   236→              }),
   237→          };
   238→
   239→          const payment: propsItems = {
   240→            ...invoiceCardData(
   241→              simulationReducer.isLoading,
   242→              !!simulationReducer.data,
   243→              !(invoicesData.length === 1 && invoice.Situacao === 'default'),
   244→              isAutoDebt
   245→            )[invoice?.Situacao ?? 'default'],
   246→            id: invoice.Fechamento,
   247→            situation: invoice?.Situacao ?? 'default',
   248→            dueDate: invoice.Vencimento,
   249→            invoiceValue: formatToCurrency(invoice.Valor),
   250→            dueDateTextLeft: invoice.VencimentoOriginal
   251→              ? moment(invoice.VencimentoOriginal).format('DD [de] MMMM')
   252→              : '-',
   253→            dueDateTextRight: formatToCurrency(invoice.ValorPgtoMinimo),
   254→            textPriceDebit: formatToCurrency(invoice.ValorPago),
   255→            hasInstallmentAvailable: !!invoice?.ParcelamentoDisponivel,
   256→          };
   257→
   258→          return {
   259→            ...invoiceCardObj,
   260→            rightButtonOnPress: () =>
   261→              handleNavigateToPayInvoice('parcelar', payment),
   262→            leftButtonOnPress: () =>
   263→              handleNavigateToPayInvoice('pagar_fatura', payment),
   264→            onPressButton: () =>
   265→              handleNavigateToPayInvoice('antecipar_pagamento', payment),
   266→          };
   267→        })
   268→        .reverse(),
   269→    [invoicesData, invoiceCardData, simulationReducer]
   270→  );
   271→
   272→  useEffect(() => {
   273→    if (!isLoading && invoicesData.length && !route.params?.dueDate) {
   274→      const currentIndex = getCurrentInvoice();
   275→      if (currentIndex >= 0) {
   276→        scrollToIndexInvoiceCards(currentIndex, false);
   277→      }
   278→    }
   279→
   280→    if (route.params?.dueDate) {
   281→      const index = invoicesCard.findIndex(
   282→        (invoice) => route.params?.dueDate === invoice.dueDate
   283→      );
   284→      if (index >= 0) {
   285→        setCurrentInvoice(index);
   286→        scrollToIndexInvoiceCards(index);
   287→      }
   288→    }
   289→  }, [isLoading, invoicesData, route.params?.dueDate, route.params?.date]);
   290→
   291→  useEffect(() => {
   292→    getInvoices();
   293→  }, []);
   294→
   295→  useEffect(() => {
   296→    downloadInvoiceClear();
   297→    simulationRequest(() => {});
   298→    requestAll();
   299→  }, []);
   300→
   301→  useEffect(() => {
   302→    setDownloadError(downloadInvoiceReducer?.isError ?? false);
   303→  }, [downloadInvoiceReducer?.isError, downloadInvoiceReducer?.isLoading]);
   304→
   305→  useEffect(() => {
   306→    requestTransactions();
   307→    requestBalance();
   308→  }, [currentInvoice]);
   309→
   310→  useLayoutEffect(() => {
   311→    requestPointsBalance()
   312→    requestPointsProducts()
   313→  }, []);
   314→
   315→  const { snackBarExemptionEligibleInvoice, isLoadingCardEligible } =
   316→    useSnackBarExemptionEligibleInvoice({
   317→      isLoading,
   318→      isLoadingExemptionEligibility,
   319→      invoicesCard,
   320→      invoicesData,
   321→      isError,
   322→      downloadError,
   323→      downloadInvoiceReducer,
   324→      currentInvoice,
   325→      hasExemptionEligible,
   326→    });
   327→
   328→  const handleScroll = (index: number) => {
   329→    setCurrentInvoice(index);
   330→  };
   331→
   332→  const scrollToIndexInvoiceCards = (index: number, immediate = true) => {
   333→    if (
   334→      refCardInvoiceGroup.current &&
   335→      typeof index === 'number' &&
   336→      index >= 0
   337→    ) {
   338→      setTimeout(
   339→        () => {
   340→          refCardInvoiceGroup.current?.scrollToIndex({
   341→            index: index,
   342→            animated: true,
   343→          });
   344→        },
   345→        immediate ? undefined : 100
   346→      );
   347→    }
   348→  };
   349→
   350→  const scrollToIndexFailed = (offset: number) => {
   351→    if (debounceScroll.current) {
   352→      clearInterval(debounceScroll.current);
   353→    }
   354→
   355→    debounceScroll.current = setTimeout(() => {
   356→      refCardInvoiceGroup.current?.scrollToOffset({
   357→        offset,
   358→        animated: true,
   359→      });
   360→    }, 500);
   361→  };
   362→
   363→  const onPressExtractTab = (item?: propsItemsExtractTab) => {
   364→    if (!item) {
   365→      return;
   366→    }
   367→
   368→    const index = invoicesCard.findIndex(
   369→      (invoice) => item.id === Number(invoice.id.replace(/-/g, ''))
   370→    );
   371→
   372→    setCurrentInvoice(index);
   373→    scrollToIndexInvoiceCards(index);
   374→  };
   375→
   376→  const handleGoBack = () => {
   377→    navigation.goBack();
   378→  };
   379→
   380→  const getInvoices = () => {
   381→    invoicesFintechRequest();
   382→  };
   383→
   384→  const handleNavigateToRescue = () => {
   385→    navigation.navigate('InvoiceCashback', {
   386→      campaingId: route?.params?.campaingId,
   387→      productCode: route?.params?.productCode,
   388→      pointsQuantity: pointsReducer?.pointsQuantity,
   389→      conversionFactor: pointsReducer?.convertionFactor,
   390→    });
   391→  }
   392→
   393→  const handleNavigateToCashback = () => {
   394→    eventSelectContent({
   395→      content_type: 'cta',
   396→      content_id: 'usar_cashback',
   397→      location_1: 'autosservico',
   398→      location_2: 'spmais',
   399→      location_3: 'faturas_spmais',
   400→    });
   401→
   402→    navigation.navigate(featuresReducer.rewardProgram ?  'InvoiceCashback' : 'Cashback', {
   403→      analytics: {
   404→        screen_name: 'spmais',
   405→        screen_class: 'faturas_spmais',
   406→        screen_bussines: 'autosservico',
   407→        screen_info: {
   408→          location_1: 'autosservico',
   409→          location_2: 'spmais',
   410→          location_3: 'faturas_spmais',
   411→        },
   412→      },
   413→    });
   414→  };
   415→
   416→  const handleNavigateToHistory = () => {
   417→    navigation.navigate('InvoicesHistory');
   418→  };
   419→
   420→  const debounceInvoiceRequest = (index: number) => {
   421→    if (debounceInvoice.current) {
   422→      clearTimeout(debounceInvoice.current);
   423→    }
   424→    debounceInvoice.current = setTimeout(() => {
   425→      invoiceCancelRequest();
   426→      invoiceFintechRequest(String(invoiceMonths?.[index]?.id));
   427→    }, 200);
   428→  };
   429→
   430→  const requestTransactions = () => {
   431→    invoiceCancelRequest();
   432→    debounceInvoiceRequest(currentInvoice ?? 0);
   433→  };
   434→
   435→  const invoiceMonthsFormatted = useMemo(() => {
   436→    const currentInvoiceMonth = invoiceMonths.map(
   437→      (month, index) =>
   438→        ({
   439→          ...month,
   440→          isActive: index === (currentInvoice ?? 0),
   441→        }) as propsItemsExtractTab
   442→    );
   443→    return [
   444→      ...addInvoiceMonth(2, 'subtract', invoiceMonths).reverse(),
   445→      ...currentInvoiceMonth,
   446→      ...addInvoiceMonth(2, 'add', invoiceMonths),
   447→    ];
   448→  }, [invoiceMonths, currentInvoice]);
   449→
   450→  const downloadPDF = (currentInvoicesCard: invoicesCardProps) => {
   451→    setDownloadError(false);
   452→    const cpf = customerReducer.document as string;
   453→    const date = currentInvoicesCard?.dueDate ?? new Date().toISOString();
   454→    const canDownload = currentInvoicesCard?.situation !== 'Em Aberto';
   455→    if (canDownload) {
   456→      eventSelectContent({
   457→        content_type: 'select',
   458→        content_id: 'dowload_fatura',
   459→        location_1: 'autosservico',
   460→        location_2: 'spmais',
   461→        location_3: 'faturas_spmais',
   462→      });
   463→      downloadInvoiceRequest(cpf, date);
   464→    }
   465→  };
   466→
   467→  const view = useMemo(() => {
   468→    if (isLoading || isLoadingExemptionEligibility || !invoicesCard?.length) {
   469→      return <AnimationArrows />;
   470→    }
   471→
   472→    if ((!invoicesData?.length || !invoicesCard?.length) && !isError) {
   473→      return <AnimationArrows />;
   474→    }
   475→
   476→    if (!isLoading && isError) {
   477→      return (
   478→        <BasicScreen leftIconOnPress={handleGoBack} title="Faturas">
   479→          <ApiError
   480→            onPress={() => {
   481→              getInvoices();
   482→            }}
   483→          />
   484→        </BasicScreen>
   485→      );
   486→    }
   487→
   488→    if (!invoicesCard || invoicesCard.length === 0) {
   489→      return <AnimationArrows />;
   490→    }
   491→
   492→    if (
   493→      downloadError ||
   494→      (downloadInvoiceReducer.isError && !downloadInvoiceReducer.isLoading)
   495→    ) {
   496→      return (
   497→        <BasicScreen
   498→          leftIconOnPress={() => {
   499→            downloadInvoiceClear();
   500→            setDownloadError(false);
   501→          }}
   502→          title="Faturas"
   503→        >
   504→          <ApiError onPress={downloadPDF} />
   505→        </BasicScreen>
   506→      );
   507→    }
   508→
   509→    if (!isLoading && !isError && invoicesCard?.length > 0) {
   510→      return (
   511→        <InvoiceCardView
   512→          invoiceMonths={invoiceMonthsFormatted}
   513→          currentInvoice={currentInvoice ?? getCurrentInvoice()}
   514→          handleScroll={handleScroll}
   515→          handleGoBack={handleGoBack}
   516→          invoicesExtract={invoicesExtract}
   517→          invoicesCard={invoicesCard}
   518→          handleNavigateToHistory={handleNavigateToHistory}
   519→          fintechCashbackReducer={fintechCashbackReducer}
   520→          handleNavigateToRescue={handleNavigateToRescue}
   521→          handleNavigateToCashback={handleNavigateToCashback}
   522→          downloadPDF={downloadPDF}
   523→          isLoadingInvoice={isLoadingInvoice}
   524→          hasErrorInvoice={hasErrorInvoice}
   525→          requestTransactions={requestTransactions}
   526→          isLoading={downloadInvoiceReducer.isLoading}
   527→          cashbackFeatureToggle={featuresReducer.cashBackFintech}
   528→          onPressExtractTab={onPressExtractTab}
   529→          refCardInvoiceGroup={refCardInvoiceGroup}
   530→          scrollToIndexFailed={scrollToIndexFailed}
   531→          route={route}
   532→          snackBarExemptionEligibleInvoice={
   533→            snackBarExemptionEligibleInvoice ?? DEFAULT_SNACKBAR_PROPS
   534→          }
   535→          selectedBenefit={selectedBenefit.current || undefined}
   536→          benefitsModalizeRef={benefitsModalizeRef}
   537→          insuranceList={insuranceList}
   538→          handleOpenBenefitsModalize={handleOpenBenefitsModalize}
   539→          isLoadingCardEligible={isLoadingCardEligible}
   540→          rewardProgramFeature={featuresReducer.rewardProgram}
   541→          balance={pointsReducer?.points}
   542→          hasErrorBalancePoints={pointsReducer?.isErrorBalance}
   543→        />
   544→      );
   545→    }
   546→
   547→    return null;
   548→  }, [
   549→    currentInvoice,
   550→    invoiceMonths,
   551→    invoicesExtract,
   552→    invoicesCard,
   553→    fintechCashbackReducer,
   554→    automaticDebtReducer,
   555→    isLoading,
   556→    isError,
   557→    downloadInvoiceReducer,
   558→    isLoadingInvoice,
   559→    featuresReducer,
   560→    downloadError,
   561→    isLoadingExemptionEligibility,
   562→    snackBarExemptionEligibleInvoice,
   563→  ]);
   564→
   565→  return view;
   566→};
   567→
   568→export const mapStateToProps = ({
   569→  invoicesFintechReducer,
   570→  invoiceFintechReducer,
   571→  automaticDebtReducer,
   572→  customerReducer,
   573→  downloadInvoiceReducer,
   574→  fintechCashbackReducer,
   575→  simulationReducer,
   576→  featuresReducer,
   577→  microInsuranceReducer,
   578→  pointsReducer
   579→}: AppReducers) => ({
   580→  invoicesFintechReducer,
   581→  invoiceFintechReducer,
   582→  automaticDebtReducer,
   583→  customerReducer,
   584→  downloadInvoiceReducer,
   585→  fintechCashbackReducer,
   586→  simulationReducer,
   587→  featuresReducer,
   588→  insuranceList: microInsuranceReducer?.insuranceList,
   589→  pointsReducer
   590→});
   591→
   592→export const mapDispatchToProps = (dispatch: Dispatch) => {
   593→  return bindActionCreators(
   594→    {
   595→      ...invoiceFintechActions,
   596→      ...invoicesFintechActions,
   597→      ...invoicesListFintechActions,
   598→      ...downloadInvoiceActions,
   599→      ...simulationActions,
   600→      ...productsAction,
   601→      ...exemptionEligibilityActions,
   602→      ...ContentActions,
   603→      ...activitiesActions,
   604→      ...PointsActions,
   605→      ...CashbackActions,
   606→    },
   607→    dispatch
   608→  );
   609→};
   610→
   611→export default connect(mapStateToProps, mapDispatchToProps)(InvoiceCard);
