import { propsItems } from '@semparar/design-system-app/src/atomic/fintech/CardClosedInvoice/Models/index';
import { PropsItems as ExtractTabPropsItems } from '@semparar/design-system-app/src/atomic/fintech/ExtractTab/Models';
import { propsItemsExtractTab } from '@semparar/design-system-app/src/atomic/molecules/ExtractTab/Models';
import { MaskService } from 'react-native-masked-text';
import { connect } from 'react-redux';
import { bindActionCreators, Dispatch } from 'redux';
import { useScreenViewTracking } from '~/hooks/tracking';

import AnimationArrows from '../../atomic/atoms/AnimationArrows';
import ApiError from '../../atomic/organisms/ApiError';
import BasicScreen from '../../atomic/templates/BasicScreen';
import useContents from '../../hooks/useContents';
import { useProductAndContentQuery } from '../../hooks/useProductAndContentQuery';
import { ContentActions } from '../../redux/ducks/contents';
import { productsAction } from '../../redux/ducks/customers/products';
import { downloadInvoiceActions } from '../../redux/ducks/downloadInvoice';
import { exemptionEligibilityActions } from '../../redux/ducks/exemptionEligibility';
import { invoiceFintechActions } from '../../redux/ducks/invoice';
import { invoicesFintechActions } from '../../redux/ducks/invoices';
import { invoicesListFintechActions } from '../../redux/ducks/invoicesList';
import { activitiesActions } from '../../redux/ducks/recentActivities';
import { Creators as CashbackActions } from '../../redux/ducks/cashback';

import React, {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
  useLayoutEffect,
} from 'react';
import { FlatList } from 'react-native';
import { eventSelectContent } from '~/constants/functions';

import { simulationActions } from '../../redux/ducks/simulation';
import { AppReducers } from '../../redux/reducers/Models';
import { moment } from '../../services/moment';
import { formatToCurrency, getActiveInvoice } from '../../utils/functions';
import { Benefit } from '../Benefits/Models';
import { invoiceCardData } from './data';
import {
  invoiceCardDataRebrand,
  InvoiceItemsType,
} from './data/invoiceCardDataRebrand';
import {
  InvoiceCardProps,
  InvoiceCardViewProps,
  invoicesCardProps,
} from './Models';
import InvoiceCardView from './view';

import { IHandles } from 'react-native-modalize/lib/options';
import { useSnackBarExemptionEligibleInvoice } from '../../hooks/useSnackBarExemptionEligibleInvoice';
import { DEFAULT_SNACKBAR_PROPS } from '../../hooks/useSnackBarExemptionEligibleInvoice/data';
import { PointsActions } from '../../redux/ducks/points';

const addInvoiceMonth = (
  qtd: number,
  type: 'subtract' | 'add',
  invoiceMonths: ExtractTabPropsItems[] & { dueDate?: number }[]
) => {
  return Array.from({ length: qtd }).map((_, index) => {
    const referenceMonthObj =
      invoiceMonths[type === 'subtract' ? 0 : invoiceMonths.length - 1];

    const maskedDate = MaskService.toMask(
      'custom',
      String(referenceMonthObj?.dueDate),
      {
        mask: '9999/99/99',
      }
    );

    const nextMonth = moment(maskedDate, 'YYYY/MM/DD')[type](index + 1, 'M');

    return {
      id: Number(nextMonth.format('YYYYMMDD')),
      numMonth: nextMonth.month(),
      monthActive: false,
      label: nextMonth.format('MMM'),
      isActive: false,
      disabled: true,
    };
  });
};

const InvoiceCard = ({
  navigation,
  invoicesFintechReducer: {
    invoiceMonths,
    data: invoicesData,
    isLoading,
    isError,
  },
  invoiceFintechRequest,
  invoiceCancelRequest,
  invoiceFintechReducer: {
    invoicesExtract,
    isLoading: isLoadingInvoice,
    isError: hasErrorInvoice,
  },
  automaticDebtReducer,
  fintechCashbackReducer,
  customerReducer,
  downloadInvoiceReducer,
  downloadInvoiceClear,
  downloadInvoiceRequest,
  route,
  invoicesFintechRequest,
  simulationReducer,
  simulationRequest,
  featuresReducer,
  productRequest,
  requestExemptionEligibility,
  requestContents,
  requestActivities,
  insuranceList,
  pointsReducer,
  requestPointsBalance,
  requestPointsProducts,
  requestBalance
}: InvoiceCardProps) => {
  const benefitsModalizeRef = useRef<IHandles | null>(null);

  useScreenViewTracking({ route, title: 'Faturas' });
  const {
    requestAll,
    isLoadingExemptionEligibility,
    hasExemptionEligible,
    handleCheckExemptionEligibility,
  } = useProductAndContentQuery({
    requestExemptionEligibility,
    requestContents,
    productRequest,
    requestActivities,
  });

  const getCurrentInvoice = () => {
    if (invoicesData?.length > 0) {
      return getActiveInvoice(invoicesData)?.index || 0;
    }
    return 0;
  };

  const [currentInvoice, setCurrentInvoice] = useState(getCurrentInvoice());
  const [downloadError, setDownloadError] = useState<boolean>(false);
  const refCardInvoiceGroup = useRef<FlatList | null>(null);
  const debounceInvoice = useRef<NodeJS.Timeout | null>(null);
  const debounceScroll = useRef<NodeJS.Timeout | null>(null);

  const isAutoDebt = !!automaticDebtReducer.data?.isActive;

  const handleNavigateToPayInvoice = (
    content_id: string,
    payment: propsItems
  ) => {
    eventSelectContent({
      content_type: 'cta',
      content_id,
      location_1: 'autosservico',
      location_2: 'spmais',
      location_3: 'faturas_spmais',
    });
    navigation.navigate('PayInvoice', {
      payment,
      analytics: {
        screen_name: 'spmais',
        screen_class: 'faturas_spmais',
        screen_bussines: 'autosservico',
        screen_info: {
          location_1: 'autosservico',
          location_2: 'spmais',
          location_3: 'faturas_spmais',
        },
      },
    });
  };

  const selectedBenefit = useRef<Benefit>(null);

  const { benefits } = useContents(handleCheckExemptionEligibility);

  useEffect(() => {
    if (
      Reflect.has(benefits, 'MONTHLY_FEE_EXEMPTION') &&
      !selectedBenefit.current
    ) {
      selectedBenefit.current = benefits?.MONTHLY_FEE_EXEMPTION;
    }
  }, [selectedBenefit, benefits]);

  const handleOpenBenefitsModalize = useCallback(() => {
    benefitsModalizeRef.current?.open?.();
  }, [benefitsModalizeRef]);

  const invoicesCard: InvoiceCardViewProps['invoicesCard'] = useMemo(
    () =>
      invoicesData
        ?.map((invoice) => {
          const invoiceCardObj: InvoiceCardViewProps['invoicesCard'][number] = {
            ...invoiceCardDataRebrand(
              simulationReducer.isLoading,
              !!simulationReducer.data,
              !(invoicesData.length === 1 && invoice.Situacao === 'default'),
              !!invoice?.ParcelamentoDisponivel
            )[(invoice?.Situacao ?? 'default') as InvoiceItemsType],
            id: invoice.Fechamento,
            dueDate: invoice.Vencimento,
            balance: formatToCurrency(invoice.Valor),
            leftItems: [
              {
                label: 'Vencimento',
                labelColor: 'INTENSE_COLOR_04',
                value: invoice.VencimentoOriginal
                  ? moment(invoice.VencimentoOriginal).format('DD [de] MMMM')
                  : '-',
                valueColor: 'BRAND_COMPLEMENT_01',
              },
            ],
            rightItems: [
              {
                label: 'Pagamento mínimo',
                labelColor: 'INTENSE_COLOR_04',
                value: formatToCurrency(invoice.ValorPgtoMinimo),
                valueColor: 'BRAND_COMPLEMENT_01',
              },
            ],
            ...(invoice.MelhorDiaCompra &&
              (invoice.Situacao === 'closed' ||
                invoice.Situacao === 'open' ||
                invoice.Situacao === 'default') && {
                description: `Melhor dia de compra: ${moment(
                  invoice.MelhorDiaCompra
                ).format('DD/MM')}`,
                descriptionIcon: 'icon-calendar',
              }),
          };

          const payment: propsItems = {
            ...invoiceCardData(
              simulationReducer.isLoading,
              !!simulationReducer.data,
              !(invoicesData.length === 1 && invoice.Situacao === 'default'),
              isAutoDebt
            )[invoice?.Situacao ?? 'default'],
            id: invoice.Fechamento,
            situation: invoice?.Situacao ?? 'default',
            dueDate: invoice.Vencimento,
            invoiceValue: formatToCurrency(invoice.Valor),
            dueDateTextLeft: invoice.VencimentoOriginal
              ? moment(invoice.VencimentoOriginal).format('DD [de] MMMM')
              : '-',
            dueDateTextRight: formatToCurrency(invoice.ValorPgtoMinimo),
            textPriceDebit: formatToCurrency(invoice.ValorPago),
            hasInstallmentAvailable: !!invoice?.ParcelamentoDisponivel,
          };

          return {
            ...invoiceCardObj,
            rightButtonOnPress: () =>
              handleNavigateToPayInvoice('parcelar', payment),
            leftButtonOnPress: () =>
              handleNavigateToPayInvoice('pagar_fatura', payment),
            onPressButton: () =>
              handleNavigateToPayInvoice('antecipar_pagamento', payment),
          };
        })
        .reverse(),
    [invoicesData, invoiceCardData, simulationReducer]
  );

  useEffect(() => {
    if (!isLoading && invoicesData.length && !route.params?.dueDate) {
      const currentIndex = getCurrentInvoice();
      if (currentIndex >= 0) {
        scrollToIndexInvoiceCards(currentIndex, false);
      }
    }

    if (route.params?.dueDate) {
      const index = invoicesCard.findIndex(
        (invoice) => route.params?.dueDate === invoice.dueDate
      );
      if (index >= 0) {
        setCurrentInvoice(index);
        scrollToIndexInvoiceCards(index);
      }
    }
  }, [isLoading, invoicesData, route.params?.dueDate, route.params?.date]);

  useEffect(() => {
    getInvoices();
  }, []);

  useEffect(() => {
    downloadInvoiceClear();
    simulationRequest(() => {});
    requestAll();
  }, []);

  useEffect(() => {
    setDownloadError(downloadInvoiceReducer?.isError ?? false);
  }, [downloadInvoiceReducer?.isError, downloadInvoiceReducer?.isLoading]);

  useEffect(() => {
    requestTransactions();
    requestBalance();
  }, [currentInvoice]);

  useLayoutEffect(() => {
    requestPointsBalance()
    requestPointsProducts()
  }, []);

  const { snackBarExemptionEligibleInvoice, isLoadingCardEligible } =
    useSnackBarExemptionEligibleInvoice({
      isLoading,
      isLoadingExemptionEligibility,
      invoicesCard,
      invoicesData,
      isError,
      downloadError,
      downloadInvoiceReducer,
      currentInvoice,
      hasExemptionEligible,
    });

  const handleScroll = (index: number) => {
    setCurrentInvoice(index);
  };

  const scrollToIndexInvoiceCards = (index: number, immediate = true) => {
    if (
      refCardInvoiceGroup.current &&
      typeof index === 'number' &&
      index >= 0
    ) {
      setTimeout(
        () => {
          refCardInvoiceGroup.current?.scrollToIndex({
            index: index,
            animated: true,
          });
        },
        immediate ? undefined : 100
      );
    }
  };

  const scrollToIndexFailed = (offset: number) => {
    if (debounceScroll.current) {
      clearInterval(debounceScroll.current);
    }

    debounceScroll.current = setTimeout(() => {
      refCardInvoiceGroup.current?.scrollToOffset({
        offset,
        animated: true,
      });
    }, 500);
  };

  const onPressExtractTab = (item?: propsItemsExtractTab) => {
    if (!item) {
      return;
    }

    const index = invoicesCard.findIndex(
      (invoice) => item.id === Number(invoice.id.replace(/-/g, ''))
    );

    setCurrentInvoice(index);
    scrollToIndexInvoiceCards(index);
  };

  const handleGoBack = () => {
    navigation.goBack();
  };

  const getInvoices = () => {
    invoicesFintechRequest();
  };

  const handleNavigateToRescue = () => {
    navigation.navigate('InvoiceCashback', {
      campaingId: route?.params?.campaingId,
      productCode: route?.params?.productCode,
      pointsQuantity: pointsReducer?.pointsQuantity,
      conversionFactor: pointsReducer?.convertionFactor,
    });
  }

  const handleNavigateToCashback = () => {
    eventSelectContent({
      content_type: 'cta',
      content_id: 'usar_cashback',
      location_1: 'autosservico',
      location_2: 'spmais',
      location_3: 'faturas_spmais',
    });

    navigation.navigate(featuresReducer.rewardProgram ?  'InvoiceCashback' : 'Cashback', {
      analytics: {
        screen_name: 'spmais',
        screen_class: 'faturas_spmais',
        screen_bussines: 'autosservico',
        screen_info: {
          location_1: 'autosservico',
          location_2: 'spmais',
          location_3: 'faturas_spmais',
        },
      },
    });
  };

  const handleNavigateToHistory = () => {
    navigation.navigate('InvoicesHistory');
  };

  const debounceInvoiceRequest = (index: number) => {
    if (debounceInvoice.current) {
      clearTimeout(debounceInvoice.current);
    }
    debounceInvoice.current = setTimeout(() => {
      invoiceCancelRequest();
      invoiceFintechRequest(String(invoiceMonths?.[index]?.id));
    }, 200);
  };

  const requestTransactions = () => {
    invoiceCancelRequest();
    debounceInvoiceRequest(currentInvoice ?? 0);
  };

  const invoiceMonthsFormatted = useMemo(() => {
    const currentInvoiceMonth = invoiceMonths.map(
      (month, index) =>
        ({
          ...month,
          isActive: index === (currentInvoice ?? 0),
        }) as propsItemsExtractTab
    );
    return [
      ...addInvoiceMonth(2, 'subtract', invoiceMonths).reverse(),
      ...currentInvoiceMonth,
      ...addInvoiceMonth(2, 'add', invoiceMonths),
    ];
  }, [invoiceMonths, currentInvoice]);

  const downloadPDF = (currentInvoicesCard: invoicesCardProps) => {
    setDownloadError(false);
    const cpf = customerReducer.document as string;
    const date = currentInvoicesCard?.dueDate ?? new Date().toISOString();
    const canDownload = currentInvoicesCard?.situation !== 'Em Aberto';
    if (canDownload) {
      eventSelectContent({
        content_type: 'select',
        content_id: 'dowload_fatura',
        location_1: 'autosservico',
        location_2: 'spmais',
        location_3: 'faturas_spmais',
      });
      downloadInvoiceRequest(cpf, date);
    }
  };

  const view = useMemo(() => {
    if (isLoading || isLoadingExemptionEligibility || !invoicesCard?.length) {
      return <AnimationArrows />;
    }

    if ((!invoicesData?.length || !invoicesCard?.length) && !isError) {
      return <AnimationArrows />;
    }

    if (!isLoading && isError) {
      return (
        <BasicScreen leftIconOnPress={handleGoBack} title="Faturas">
          <ApiError
            onPress={() => {
              getInvoices();
            }}
          />
        </BasicScreen>
      );
    }

    if (!invoicesCard || invoicesCard.length === 0) {
      return <AnimationArrows />;
    }

    if (
      downloadError ||
      (downloadInvoiceReducer.isError && !downloadInvoiceReducer.isLoading)
    ) {
      return (
        <BasicScreen
          leftIconOnPress={() => {
            downloadInvoiceClear();
            setDownloadError(false);
          }}
          title="Faturas"
        >
          <ApiError onPress={downloadPDF} />
        </BasicScreen>
      );
    }

    if (!isLoading && !isError && invoicesCard?.length > 0) {
      return (
        <InvoiceCardView
          invoiceMonths={invoiceMonthsFormatted}
          currentInvoice={currentInvoice ?? getCurrentInvoice()}
          handleScroll={handleScroll}
          handleGoBack={handleGoBack}
          invoicesExtract={invoicesExtract}
          invoicesCard={invoicesCard}
          handleNavigateToHistory={handleNavigateToHistory}
          fintechCashbackReducer={fintechCashbackReducer}
          handleNavigateToRescue={handleNavigateToRescue}
          handleNavigateToCashback={handleNavigateToCashback}
          downloadPDF={downloadPDF}
          isLoadingInvoice={isLoadingInvoice}
          hasErrorInvoice={hasErrorInvoice}
          requestTransactions={requestTransactions}
          isLoading={downloadInvoiceReducer.isLoading}
          cashbackFeatureToggle={featuresReducer.cashBackFintech}
          onPressExtractTab={onPressExtractTab}
          refCardInvoiceGroup={refCardInvoiceGroup}
          scrollToIndexFailed={scrollToIndexFailed}
          route={route}
          snackBarExemptionEligibleInvoice={
            snackBarExemptionEligibleInvoice ?? DEFAULT_SNACKBAR_PROPS
          }
          selectedBenefit={selectedBenefit.current || undefined}
          benefitsModalizeRef={benefitsModalizeRef}
          insuranceList={insuranceList}
          handleOpenBenefitsModalize={handleOpenBenefitsModalize}
          isLoadingCardEligible={isLoadingCardEligible}
          rewardProgramFeature={featuresReducer.rewardProgram}
          balance={pointsReducer?.points}
          hasErrorBalancePoints={pointsReducer?.isErrorBalance}
        />
      );
    }

    return null;
  }, [
    currentInvoice,
    invoiceMonths,
    invoicesExtract,
    invoicesCard,
    fintechCashbackReducer,
    automaticDebtReducer,
    isLoading,
    isError,
    downloadInvoiceReducer,
    isLoadingInvoice,
    featuresReducer,
    downloadError,
    isLoadingExemptionEligibility,
    snackBarExemptionEligibleInvoice,
  ]);

  return view;
};

export const mapStateToProps = ({
  invoicesFintechReducer,
  invoiceFintechReducer,
  automaticDebtReducer,
  customerReducer,
  downloadInvoiceReducer,
  fintechCashbackReducer,
  simulationReducer,
  featuresReducer,
  microInsuranceReducer,
  pointsReducer
}: AppReducers) => ({
  invoicesFintechReducer,
  invoiceFintechReducer,
  automaticDebtReducer,
  customerReducer,
  downloadInvoiceReducer,
  fintechCashbackReducer,
  simulationReducer,
  featuresReducer,
  insuranceList: microInsuranceReducer?.insuranceList,
  pointsReducer
});

export const mapDispatchToProps = (dispatch: Dispatch) => {
  return bindActionCreators(
    {
      ...invoiceFintechActions,
      ...invoicesFintechActions,
      ...invoicesListFintechActions,
      ...downloadInvoiceActions,
      ...simulationActions,
      ...productsAction,
      ...exemptionEligibilityActions,
      ...ContentActions,
      ...activitiesActions,
      ...PointsActions,
      ...CashbackActions,
    },
    dispatch
  );
};

export default connect(mapStateToProps, mapDispatchToProps)(InvoiceCard);

