+import { useCallback } from 'react';
+import { useSelector } from 'react-redux';
+import { getAcountNumber } from '../../../hooks/useSelectors';
+import { invoiceCashbackPermissionService } from '../services';
+import { useInvoiceCashbackPermissionStore } from './useInvoiceCashbackPermissionStore';
+
+export function useInvoiceCashbackPermission() {
+  const accountId = useSelector(getAcountNumber);
+
+  const { hasRedeemed, isLoading, isError } = useInvoiceCashbackPermissionStore(
+    (state) => state.invoiceCashbackPermission
+  );
+
+  const { setHasRedeemed, setLoading, setError } = useInvoiceCashbackPermissionStore(
+    (state) => state.invoiceCashbackPermissionActions
+  );
+
+  const checkHasRedeemed = useCallback(
+    async ({ showLoading = false }: { showLoading?: boolean } = {}): Promise<boolean> => {
+      if (!accountId) {
+        return false;
+      }
+
+      if (showLoading) {
+        setLoading(true);
+      }
+
+      try {
+        const result = await invoiceCashbackPermissionService.hasRedeemed(accountId);
+        setHasRedeemed(result);
+        return result;
+      } catch {
+        setError(true);
+        return false;
+      }
+    },
+    [accountId, setHasRedeemed, setLoading, setError]
+  );
+
+  const markAsRedeemed = useCallback(async (): Promise<boolean> => {
+    if (!accountId) {
+      return false;
+    }
+
+    try {
+      await invoiceCashbackPermissionService.markAsRedeemed(accountId);
+      setHasRedeemed(true);
+      return true;
+    } catch {
+      return false;
+    }
+  }, [accountId, setHasRedeemed]);
+
+  return {
+    hasRedeemed,
+    isLoading,
+    isError,
+    checkHasRedeemed,
+    markAsRedeemed,
+  };
+}
